<?phpclass Member_model extends CI_Model {	    public function record_count() {        return $this->db->count_all('member');    }	public function getall() {		$query = $this->db->order_by('nama', 'asc')->get('member');				if ($query->num_rows() > 0)			return $query->result_array();		else			return 0;	}	public function get($id) {		$query = $this->db->where('id', $id)->get('member', 1, 0);		if ($query->num_rows() > 0)			return $query->result_array();		else			return 0;	}		public function get_birthday() {		$toro = "select * from member where ";		for ($i = 0; $i < 30; $i++) {			$nowmonth = date('m', strtotime('+'.$i.' days'));			$nowday = date('d', strtotime('+'.$i.' days'));			if ($i == 0)				$toro .= "(day(tanggal_lahir)=".$nowday." and month(tanggal_lahir)=".$nowmonth.")";			else				$toro .= " or (day(tanggal_lahir)=".$nowday." and month(tanggal_lahir)=".$nowmonth.")";		}		$toro .= " order by month(tanggal_lahir), day(tanggal_lahir) limit 10";		$query = $this->db->query($toro);				if ($query->num_rows() > 0)			return $query->result_array();		else			return 0;	}}